SELECT teff
FROM stellar_parameters
ORDER BY mass DESC;

SELECT teff, logg, metallicity
FROM stellar_parameters
WHERE teff > 5000;

SELECT spectral_type, AVG(prot) AS avg_rotation_period
FROM stellar_parameters
GROUP BY spectral_type;

SELECT AVG(prot) AS average_rotation_period
FROM stellar_parameters
WHERE spectral_type = 'G2V';

SELECT spectral_type, luminosity
FROM stellar_parameters
ORDER BY luminosity DESC;

SELECT star_id
FROM stellar_parameters
WHERE age = (SELECT MAX(age) FROM stellar_parameters);
